def safely_read_patch_identity(
    patch_path: Path | None,
) -> tuple[str, str]:
    if patch_path is None:
        return "unknown-patch", "Unknown patch"

    try:
        resolved = patch_path.expanduser().resolve()

        if not resolved.exists() or not resolved.is_file():
            return normalize_patch_id(resolved.stem), resolved.stem

        raw = resolved.read_text(encoding="utf-8")
        data = json.loads(raw)

        if not isinstance(data, dict):
            return normalize_patch_id(resolved.stem), resolved.stem

        raw_name = data.get("name")
        patch_name = (
            raw_name.strip()
            if isinstance(raw_name, str) and raw_name.strip()
            else resolved.stem
        )

        raw_id = data.get("id")

        if isinstance(raw_id, str) and raw_id.strip():
            patch_id = normalize_patch_id(raw_id)
        else:
            patch_id = normalize_patch_id(patch_name)

        return patch_id, patch_name

    except Exception:
        fallback = patch_path.stem or "unknown-patch"

        try:
            return normalize_patch_id(fallback), fallback
        except PatchError:
            return "unknown-patch", "Unknown patch"


def summarize_failed_operation(
    operation: dict[str, Any] | None,
) -> dict[str, Any] | None:
    if operation is None:
        return None

    summary: dict[str, Any] = {}

    for key in (
        "operation",
        "file",
        "from",
        "to",
        "expected_matches",
        "expected_sha256",
        "must_exist",
        "must_not_exist",
        "allow_overwrite",
    ):
        if key in operation:
            summary[key] = operation[key]

    find_text = operation.get("find")

    if isinstance(find_text, str):
        summary["find_preview"] = truncate_for_error(find_text)

    return summary


def derive_failure_guidance(
    error_message: str,
    stage: str,
) -> tuple[list[str], list[str]]:
    message = error_message.lower()
    likely_causes: list[str] = []
    recommended_fixes: list[str] = []

    if "invalid json" in message or stage == "schema_validation":
        likely_causes.extend(
            [
                "The patch JSON is malformed or does not match the supported schema.",
                "A required field may be missing, misspelled, or use the wrong value type.",
            ]
        )
        recommended_fixes.extend(
            [
                "Open the patch JSON and correct the reported line, column, key, or value type.",
                "Confirm that schema_version is supported and every operation uses an accepted operation type.",
                "Run npm run patch -- --dry-run after correcting the packet.",
            ]
        )

    elif "expected" in message and "match" in message:
        likely_causes.extend(
            [
                "The target source file changed after the patch was generated.",
                "The find block does not exactly match the current indentation, whitespace, or line endings.",
                "The target code may already have been modified, moved, or removed.",
            ]
        )
        recommended_fixes.extend(
            [
                "Re-read the current target file instead of relying on an older copy.",
                "Replace the stale find value with a unique exact excerpt from the current file.",
                "Keep expected_matches at 1 unless multiple replacements are intentional and verified.",
                "Run npm run patch -- --dry-run before applying the repaired patch.",
            ]
        )

    elif "sha-256" in message or "sha256" in message:
        likely_causes.extend(
            [
                "The file contents differ from the version against which the patch was authored.",
                "The expected hash may be stale or may refer to a different repository revision.",
            ]
        )
        recommended_fixes.extend(
            [
                "Inspect the current file and determine whether its changes should be preserved.",
                "Regenerate the patch against the current file state.",
                "Update expected_sha256 only after verifying the current file is the intended target.",
            ]
        )

    elif "uncommitted" in message or "dirty" in message:
        likely_causes.extend(
            [
                "One or more affected files contain uncommitted changes.",
                "Applying the patch could overwrite work that was not included when the patch was generated.",
            ]
        )
        recommended_fixes.extend(
            [
                "Review and commit or stash the affected changes before patching.",
                "Regenerate the patch if those uncommitted changes should be incorporated.",
                "Use --allow-dirty only after intentionally accepting the overwrite risk.",
            ]
        )

    elif "protected path" in message:
        likely_causes.extend(
            [
                "The patch attempts to modify a protected repository path.",
                "The requested target may be generated, sensitive, or repository-critical.",
            ]
        )
        recommended_fixes.extend(
            [
                "Confirm that the protected file genuinely needs direct modification.",
                "Prefer modifying its source or generator rather than generated output.",
                "Add only the exact required path to allow_protected_paths when the change is intentional.",
            ]
        )

    elif "risk" in message and "acknowledged" in message:
        likely_causes.extend(
            [
                "The patch performs a dangerous action that its risk metadata does not acknowledge.",
                "The risk_acceptance section may be stale or inaccurate.",
            ]
        )
        recommended_fixes.extend(
            [
                "Review the staged operation and confirm that the dangerous action is intentional.",
                "Set the corresponding risk_acceptance flag to true only when the action is required.",
                "Remove risk flags that are true when the patch does not actually perform that risk.",
            ]
        )

    elif "still be imported" in message or "references remain" in message:
        likely_causes.extend(
            [
                "A deleted or moved file is still referenced elsewhere in the repository.",
                "A removed symbol still has consumers that were not updated.",
            ]
        )
        recommended_fixes.extend(
            [
                "Locate every reported importer or symbol reference.",
                "Update consumers to use the declared replacement before deleting or moving the original.",
                "Declare the replacement in dependency_changes when functionality is being replaced.",
            ]
        )

    elif "replacement file" in message or "replacement symbol" in message:
        likely_causes.extend(
            [
                "The dependency contract names a replacement that does not exist in the staged repository.",
                "The replacement symbol may not be exported or may use a different name.",
            ]
        )
        recommended_fixes.extend(
            [
                "Ensure the replacement file is created before dependency validation runs.",
                "Confirm that the replacement symbol name exactly matches the implemented and exported symbol.",
                "Update dependency_changes to reflect the actual replacement mapping.",
            ]
        )

    elif "validation command failed" in message:
        likely_causes.extend(
            [
                "The staged repository failed a configured lint, typecheck, test, or build command.",
                "The textual patch applied successfully but produced an invalid repository state.",
            ]
        )
        recommended_fixes.extend(
            [
                "Read the command output included in the error and repair the first underlying failure.",
                "Check imports, exports, types, syntax, and test expectations affected by the patch.",
                "Run the failing command manually after repairing the patch.",
            ]
        )

    elif "timed out" in message:
        likely_causes.extend(
            [
                "A validation command exceeded the configured timeout.",
                "The command may be hanging, waiting for interaction, or performing excessive work.",
            ]
        )
        recommended_fixes.extend(
            [
                "Run the validation command manually to determine whether it waits for input or hangs.",
                "Use a non-interactive test or build command.",
                "Increase timeout_seconds only when the command is known to complete safely.",
            ]
        )

    elif stage == "postcondition_validation":
        likely_causes.extend(
            [
                "The operations applied, but the staged repository does not satisfy the declared result contract.",
                "A postcondition may be stale, incomplete, or aimed at the wrong file.",
            ]
        )
        recommended_fixes.extend(
            [
                "Compare the staged result with each declared postcondition.",
                "Correct the operations if the intended result was not produced.",
                "Correct the postcondition only when the staged result is genuinely the intended state.",
            ]
        )

    elif stage == "repository_commit":
        likely_causes.extend(
            [
                "A filesystem error occurred while committing staged files.",
                "A file may be locked, read-only, missing permissions, or changed during the commit.",
            ]
        )
        recommended_fixes.extend(
            [
                "Confirm from the terminal error whether automatic rollback completed.",
                "Check file permissions and whether another process has locked an affected file.",
                "Compare affected files with their backups before attempting the patch again.",
            ]
        )

    else:
        likely_causes.extend(
            [
                "The patch violated a repository safety condition during the reported stage.",
                "The patch may have been authored against stale or incomplete repository information.",
            ]
        )
        recommended_fixes.extend(
            [
                "Review the exact error, failure stage, and failed operation recorded in this report.",
                "Re-read the current affected files and regenerate only the failing portion of the patch.",
                "Run npm run patch -- --dry-run before applying the corrected patch.",
            ]
        )

    return likely_causes, recommended_fixes


def determine_repository_result(stage: str, message: str) -> str:
    if stage in {
        "startup",
        "loading_patch",
        "schema_validation",
        "building_patch_context",
        "reapply_policy",
        "operation_conflict_validation",
        "path_policy_validation",
        "git_policy_validation",
        "precondition_validation",
        "operation_application",
        "change_summary",
        "limit_validation",
        "risk_validation",
        "structural_validation",
        "dependency_validation",
        "postcondition_validation",
        "validation_commands",
        "reporting_success",
        "dry_run_complete",
        "backup_creation",
    }:
        return "not_modified"

    lowered = message.lower()

    if stage == "repository_commit":
        if "rolled back" in lowered:
            return "rollback_reported_successful"

        if "rollback also failed" in lowered:
            return "rollback_failed_manual_review_required"

        return "commit_state_requires_review"

    if stage in {"history_recording", "completed"}:
        return "patch_changes_committed"

    return "unknown"


def write_text_atomically(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_name(
        f".{path.name}.{os.getpid()}.tmp"
    )

    try:
        temporary.write_text(content, encoding="utf-8")
        os.replace(temporary, path)
    finally:
        if temporary.exists():
            temporary.unlink()


def render_failure_markdown(report: dict[str, Any]) -> str:
    lines = [
        "# Patch Failure Report",
        "",
        "## Patch",
        "",
        f"- ID: `{report['patch_id']}`",
        f"- Name: {report['patch_name']}",
        f"- Time: `{report['failed_at']}`",
        f"- Status: Failed safely",
        f"- Failure stage: `{report['failure_stage']}`",
        f"- Repository result: `{report['repository_result']}`",
        "",
        "## Error",
        "",
        f"- Type: `{report['error_type']}`",
        "",
        "```text",
        report["error_message"],
        "```",
        "",
    ]

    operation = report.get("failed_operation")

    if operation is not None:
        lines.extend(
            [
                "## Failed operation",
                "",
                f"- Index: `{report.get('operation_index')}`",
                f"- Type: `{operation.get('operation', 'unknown')}`",
            ]
        )

        for key in (
            "file",
            "from",
            "to",
            "expected_matches",
            "expected_sha256",
            "find_preview",
        ):
            if key in operation:
                lines.append(f"- {key}: `{operation[key]}`")

        lines.append("")

    lines.extend(
        [
            "## Likely causes",
            "",
        ]
    )

    for cause in report["likely_causes"]:
        lines.append(f"- {cause}")

    lines.extend(
        [
            "",
            "## Recommended correction",
            "",
        ]
    )

    for index, recommendation in enumerate(
        report["recommended_fixes"],
        start=1,
    ):
        lines.append(f"{index}. {recommendation}")

    lines.extend(
        [
            "",
            "## Retry command",
            "",
            "```bash",
            "npm run patch -- --dry-run",
            "```",
            "",
        ]
    )

    return "\n".join(lines)


def write_failure_feedback(
    error: BaseException,
    arguments: argparse.Namespace | None,
) -> tuple[Path, Path]:
    patch_path = (
        arguments.patch
        if arguments is not None and hasattr(arguments, "patch")
        else DEFAULT_PATCH_FILE
    )

    patch_id, patch_name = safely_read_patch_identity(patch_path)
    error_message = str(error)
    likely_causes, recommended_fixes = derive_failure_guidance(
        error_message,
        CURRENT_PATCH_STAGE,
    )

    failed_at = utc_now().isoformat()
    path_timestamp = timestamp_for_path()

    report = {
        "schema_version": 1,
        "status": "failed",
        "patch_id": patch_id,
        "patch_name": patch_name,
        "patch_file": str(patch_path.expanduser().resolve()),
        "failed_at": failed_at,
        "failure_stage": CURRENT_PATCH_STAGE,
        "operation_index": CURRENT_OPERATION_INDEX,
        "failed_operation": summarize_failed_operation(
            CURRENT_OPERATION
        ),
        "error_type": type(error).__name__,
        "error_message": error_message,
        "repository_result": determine_repository_result(
            CURRENT_PATCH_STAGE,
            error_message,
        ),
        "likely_causes": likely_causes,
        "recommended_fixes": recommended_fixes,
        "retry_command": "npm run patch -- --dry-run",
    }

    PATCH_FEEDBACK_ROOT.mkdir(parents=True, exist_ok=True)

    base_name = f"{path_timestamp}-{patch_id}"
    timestamped_json = PATCH_FEEDBACK_ROOT / f"{base_name}.json"
    timestamped_markdown = PATCH_FEEDBACK_ROOT / f"{base_name}.md"

    json_content = json.dumps(report, indent=2) + "\n"
    markdown_content = render_failure_markdown(report)

    write_text_atomically(timestamped_json, json_content)
    write_text_atomically(timestamped_markdown, markdown_content)
    write_text_atomically(
        PATCH_FEEDBACK_ROOT / "latest.json",
        json_content,
    )
    write_text_atomically(
        PATCH_FEEDBACK_ROOT / "latest.md",
        markdown_content,
    )

    return timestamped_json, timestamped_markdown


def report_failure(
    prefix: str,
    error: BaseException,
    arguments: argparse.Namespace | None,
) -> None:
    print(f"{prefix}: {error}", file=sys.stderr)

    try:
        json_path, markdown_path = write_failure_feedback(
            error,
            arguments,
        )
        print(
            "Failure feedback JSON: "
            f"{json_path.relative_to(REPOSITORY_ROOT)}",
            file=sys.stderr,
        )
        print(
            "Failure feedback Markdown: "
            f"{markdown_path.relative_to(REPOSITORY_ROOT)}",
            file=sys.stderr,
        )
    except Exception as feedback_error:
        print(
            "WARNING: The patch failed and its feedback report could "
            f"not be written: {feedback_error}",
            file=sys.stderr,
        )


def main() -> int:
    arguments: argparse.Namespace | None = None

    try:
        set_patch_stage("startup")
        arguments = parse_arguments()
        apply_patch(arguments)
        return 0

    except PatchError as error:
        report_failure("ERROR", error, arguments)
        return 1

    except KeyboardInterrupt as error:
        report_failure(
            "ERROR: Patch cancelled by user",
            error,
            arguments,
        )
        return 130

    except OSError as error:
        report_failure("FILESYSTEM ERROR", error, arguments)
        return 1

    except Exception as error:
        report_failure(
            f"UNEXPECTED ERROR: {type(error).__name__}",
            error,
            arguments,
        )
        return 1
